class OAuthClient {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.scopes = config.scopes || ['openid'];
    this.token = null;
    this.tokenExpiry = null;
  }

  async authenticate() {
    const fragment = window.location.hash.substring(1);
    const params = new URLSearchParams(fragment);
    
    const accessToken = params.get('access_token');
    const expiresIn = params.get('expires_in');
    const tokenType = params.get('token_type');
    
    if (accessToken && tokenType) {
      this.token = accessToken;
      this.tokenExpiry = Date.now() + (parseInt(expiresIn) * 1000);
      
      // Remove token from URL fragment
      window.history.replaceState({}, document.title, window.location.pathname);
      
      return true;
    }
    
    // Redirect to authorization endpoint if no token
    if (!this.token) {
      this.redirectToAuth();
      return false;
    }
    
    return true;
  }

  redirectToAuth() {
    const state = this.generateState();
    const authUrl = new URL(this.authorizationEndpoint);
    
    authUrl.searchParams.append('response_type', 'token');
    authUrl.searchParams.append('client_id', this.clientId);
    authUrl.searchParams.append('redirect_uri', this.redirectUri);
    authUrl.searchParams.append('scope', this.scopes.join(' '));
    authUrl.searchParams.append('state', state);
    
    window.location.href = authUrl.toString();
  }

  generateState() {
    return btoa(Math.random().toString(36).substring(2, 15) + 
                Math.random().toString(36).substring(2, 15));
  }

  async makeApiCall(url, options = {}) {
    if (!this.token || this.isTokenExpired()) {
      throw new Error('No valid access token available');
    }

    const headers = {
      'Authorization': `Bearer ${this.token}`,
      ...options.headers
    };

    const response = await fetch(url, {
      ...options,
      headers
    });

    if (response.status === 401) {
      this.token = null;
      this.tokenExpiry = null;
      throw new Error('Unauthorized: Token invalid or expired');
    }

    return response.json();
  }

  isTokenExpired() {
    return !this.tokenExpiry || Date.now() >= this.tokenExpiry;
  }

  logout() {
    this.token = null;
    this.tokenExpiry = null;
    window.history.replaceState({}, document.title, window.location.pathname);
  }
}

